/* Aura — ESM entry for js/glow.js (generated by build.py; do not edit). */
import "./core.js";
/* ==========================================================================
   Aura — proximity glow + pointer sheen behavior.

   One delegated pointermove listener + a live registry kept in sync by the
   core MutationObserver. A rAF loop maps each registered element's distance
   from the cursor to an eased 0..1 intensity and writes ONLY custom properties
   (--aura-glow-intensity / -x / -y, plus --aura-magnet-dx/-dy for the edge
   shine's magnetic lean) — no layout reads/writes that reflow.

   Sub-part targeting: a .aura-glow host may contain a .aura-glow__target
   child. When present, the rim glow is routed to the target instead of the
   host. The host still governs proximity detection and magnetic lean; the
   target gets --aura-glow-x/-y in its own coordinate space. The target's
   position relative to the host is cached outside the rAF frame (in a
   dedicated scheduling rAF and on resize) so no extra getBoundingClientRect
   calls occur per animation frame.

   CAVEAT — one sub-part target per host (#350): the registry caches a SINGLE
   .aura-glow__target per .aura-glow host (the first match). A widget with
   several independently-glowing sub-parts (e.g. a multi-handle slider) must
   therefore give EACH sub-part its own .aura-glow host — a single host with
   multiple .aura-glow__target children will only ever route the rim glow to
   the first one. This is by design (one cached target keeps the rAF frame free
   of per-frame getBoundingClientRect calls); the fix at the call site is
   structural, not a glow.js change.
   See docs/design/proximity-glow-design.md.
   ========================================================================== */
(function () {
  "use strict";
  /* SSR guard (#416): no-op outside the browser so SSR/RSC frameworks can
     evaluate this module (and the dist bundle) in Node without crashing. */
  if (typeof window === "undefined" || typeof document === "undefined") return;
  var Aura = window.Aura;
  if (!Aura) return;

  var glow = (Aura.glow = {
    falloff: 1.6          // easing exponent for proximity → intensity
  });

  // Touch / no-hover devices have no cursor; CSS focus states cover them.
  if (Aura.env.coarsePointer()) return;

  /* Fallback detection radius (px) when --aura-glow-radius is absent/invalid. */
  var DEFAULT_GLOW_RADIUS = 130;
  /* Far-offscreen sentinel for "cursor not over the page" (fades everything). */
  var OFFSCREEN = -9999;

  var registry = [];      // current glow/sheen elements
  var px = OFFSCREEN, py = OFFSCREEN;
  var running = false;
  var moved = false;

  // Pointer movement alone never changes element geometry, so getBoundingClientRect
  // is cached per element and only re-read when layout could have shifted —
  // scroll or resize (#41). On a still page the rAF loop then performs ZERO
  // forced synchronous layouts per frame, regardless of registry size.
  var rectsDirty = true;
  // Bumped on resize/zoom; the per-element style cache (radius/magnet/lift) is
  // keyed off it so a single re-read refreshes all three and a legitimately-zero
  // radius no longer forces a getComputedStyle every frame (#43).
  var styleEpoch = 0;

  // --------------------------------------------------------------------------
  // Sub-part target offset cache
  //
  // For hosts that have a .aura-glow__target child we pre-compute the target's
  // position relative to the host using getBoundingClientRect on BOTH elements.
  // This read happens in a dedicated rAF (outside the glow frame loop) so the
  // frame() function can derive the target's viewport rect from the live host
  // rect + the cached offset — zero extra layout reads per glow frame.
  //
  // Per-host cache properties:
  //   __auraTarget    : the .aura-glow__target descendant element, or null
  //   __auraTargetOff : { dx, dy, w, h } — target rect relative to host rect
  //                     null if not yet measured or invalidated by resize.

  var _targetCachePending = false;

  function _scheduleTargetCache() {
    if (_targetCachePending) return;
    _targetCachePending = true;
    requestAnimationFrame(function () {
      _targetCachePending = false;
      for (var i = 0; i < registry.length; i++) {
        var el = registry[i];
        if (!el.isConnected) continue;
        var t = el.querySelector(".aura-glow__target");
        // Update the cached target reference (handles DOM mutations).
        if (el.__auraTarget !== t) {
          el.__auraTarget = t || null;
          el.__auraTargetOff = null; // force re-measure
        }
        if (el.__auraTarget && !el.__auraTargetOff) {
          _readTargetOffset(el, el.__auraTarget);
        }
      }
    });
  }

  // Read and store the target's rect relative to its host. Called outside the
  // glow rAF loop (in the cache-schedule rAF or the resize handler's rAF).
  function _readTargetOffset(host, target) {
    var hr = host.getBoundingClientRect();
    var tr = target.getBoundingClientRect();
    host.__auraTargetOff = {
      dx: tr.left - hr.left,
      dy: tr.top  - hr.top,
      w:  tr.width,
      h:  tr.height
    };
  }

  // Public API: components whose sub-part target moves (e.g. the slider thumb)
  // call this after updating the target's position. Clears the stale cached
  // offset and schedules a fresh measurement on the next rAF, by which time CSS
  // will have applied the new position so getBoundingClientRect reads correctly.
  // Only defined on fine-pointer devices (coarse devices returned above).
  // Callers guard with: if (Aura.glow && Aura.glow.invalidateTarget) { … }
  glow.invalidateTarget = function(el) {
    el.__auraTargetOff = null;  // mark stale; frame() falls back to host coords
    _scheduleTargetCache();      // re-read after layout settles
  };

  // --------------------------------------------------------------------------

  /* Hidden-ancestor cache (#412). A closed overlay/nav panel often stays in
     layout while invisible (display kept for the close transition, opacity 0,
     [hidden] on the panel), so its glow items keep NONZERO rects — without
     this flag every pointer pass within radius of the footprint would compute
     distance and write custom properties to invisible elements, keeping the
     rAF loop hot under closed chrome. Cache `closest('[hidden]')` per host
     OUTSIDE the frame loop (a tree walk per frame would defeat the caches);
     refreshed on registry rebuild and on any hidden-attribute flip (the core
     observer only watches childList, so attribute toggles never reach
     onMount). Covers any current or future overlay component generically. */
  function refreshHidden() {
    for (var i = 0; i < registry.length; i++) {
      registry[i].__auraHidden = registry[i].closest("[hidden]") !== null;
    }
  }

  // Rebuild the registry whenever DOM changes (HTMX-safe via core's observer).
  Aura.onMount(function (root) {
    registry = Array.prototype.slice.call(
      document.querySelectorAll(".aura-glow, .aura-sheen")
    );
    /* Group glow (v1.7): cache each element's group name so a cluster can light
       together — every member adopts the cluster's strongest member intensity.
       Reading the attribute here keeps frame() free of DOM queries. */
    for (var i = 0; i < registry.length; i++) {
      registry[i].__auraGroup = registry[i].getAttribute("data-aura-glow-group") || null;
    }
    refreshHidden();
    _scheduleTargetCache();
  });

  /* Watch hidden-attribute flips directly (debounced to a frame) so a
     just-opened panel's items can light immediately and a just-closed panel's
     items settle back to zero — see refreshHidden() above. */
  Aura.ready(function () {
    if (!("MutationObserver" in window)) return;
    var pending = false;
    new MutationObserver(function () {
      if (pending) return;
      pending = true;
      requestAnimationFrame(function () {
        pending = false;
        refreshHidden();
        moved = true;
        start();
      });
    }).observe(document.body, {
      attributes: true,
      attributeFilter: ["hidden"],
      subtree: true
    });
  });

  /* Write an element's resolved glow intensity (change-detected), settling the
     magnetic lean back to rest as it reaches zero. Shared by the per-element
     and the group-resolution passes in frame(). */
  function applyIntensity(el, intensity) {
    var prev = el.__auraGlow || 0;
    if (intensity === prev) return;
    el.style.setProperty("--aura-glow-intensity", intensity.toFixed(3));
    if (intensity === 0 && el.__auraMagnet) {
      el.style.setProperty("--aura-magnet-dx", "0px");
      el.style.setProperty("--aura-magnet-dy", "0px");
    }
    el.__auraGlow = intensity;
  }

  /* Read the element's detection radius from --aura-glow-radius (px). */
  function radiusFor(el) {
    var v = getComputedStyle(el).getPropertyValue("--aura-glow-radius");
    var n = parseFloat(v);
    return isNaN(n) ? DEFAULT_GLOW_RADIUS : n;
  }

  // True when an element must stay matte: the documented .aura-glow--off opt-out
  // OR a disabled control (only what is genuinely clickable glows/leans). Such
  // elements get zero intensity and zero magnet so neither halo nor lean shows.
  function suppressed(el) {
    return el.classList.contains("aura-glow--off") ||
           el.matches("[disabled], [aria-disabled=\"true\"]");
  }

  // Max px a widget leans toward the cursor. Only interactive elements
  // (.aura-glow) move; glass surfaces (.aura-sheen) stay put.
  function magnetFor(el) {
    if (!el.classList.contains("aura-glow")) return 0;
    var v = getComputedStyle(el).getPropertyValue("--aura-magnet-shift");
    var n = parseFloat(v);
    return isNaN(n) ? 0 : n;
  }

  // Px a control rises on hover (CSS: transform: translateY(-lift)). The lift
  // shifts the live rect upward, so the magnet adds it back to recover the
  // control's true resting centre (see frame()).
  function liftFor(el) {
    var v = getComputedStyle(el).getPropertyValue("--aura-hover-lift");
    var n = parseFloat(v);
    return isNaN(n) ? 0 : n;
  }

  // Refresh the cached radius/magnet/lift for an element, but only when the
  // style epoch has advanced (initial read or after a resize/zoom). Keying off
  // an epoch — rather than resetting __auraRadius to a falsy 0 — means the three
  // getComputedStyle reads happen once per epoch, and a real 0 value caches
  // correctly instead of forcing a re-read every frame (#43).
  function readStyles(el) {
    if (el.__auraStyleEpoch === styleEpoch) return;
    el.__auraRadius = radiusFor(el);
    el.__auraMagnet = magnetFor(el);
    el.__auraLift = liftFor(el);
    el.__auraStyleEpoch = styleEpoch;
  }

  function frame() {
    var anyActive = false;
    var groupMax = null; // lazily created { groupName: maxIntensity }

    /* prefers-reduced-motion (#1090): the continuous distance→intensity ramp
       below (Math.pow(1 - dist/radius, falloff)) IS the Approach movement's
       animation (fmb-design.md §2 Approach; docs/design/fmb-choreography-
       design.md §The two-driver model) — every FMB member's ghost-opacity/
       grayscale calc() rides this SAME --aura-glow-intensity value (see e.g.
       css/footer.css's circle rule), so gating it here once, generically,
       covers every current and future .aura-glow/.aura-sheen consumer with
       no per-member CSS special-casing. Under reduced motion the ramp
       collapses to a single discrete step — 1 the instant the cursor is
       within the detection radius, 0 otherwise — never an intermediate
       value, so the un-ghost reads as one state swap, not a per-frame fade.
       Checked LIVE inside the frame loop (mirrors js/fmb-choreography.js's
       own Aura.env.reducedMotion()/coarsePointer() convention and that
       file's doc comment on why: a matchMedia stub installed by a test, or a
       real OS preference change, must take effect on the very next frame,
       not just at IIFE-eval time) — one matchMedia() call per frame the loop
       is actively running (idle otherwise), not per element. */
    var reduced = Aura.env.reducedMotion();

    for (var i = 0; i < registry.length; i++) {
      var el = registry[i];
      if (!el.isConnected) continue;

      // Inert hosts never light or lean: a cached [hidden]-ancestor host
      // (#412 — invisible but still in layout, see refreshHidden), the matte
      // .aura-glow--off opt-out, or a disabled control. Settle to rest
      // (intensity 0 zeroes the magnet via applyIntensity) and skip BEFORE any
      // style/rect/distance work so closed chrome costs nothing per frame.
      // Re-enabling/unhiding lets the next frame light it normally.
      if (el.__auraHidden || suppressed(el)) {
        if (el.__auraGroup) {
          if (!groupMax) groupMax = {};
          if (groupMax[el.__auraGroup] === undefined) groupMax[el.__auraGroup] = 0;
        } else {
          applyIntensity(el, 0);
        }
        continue;
      }

      readStyles(el);
      // Reuse the cached rect unless layout may have moved (scroll/resize) or
      // this element has not been measured yet — pointer-only frames read no
      // layout at all (#41).
      var rect = (!rectsDirty && el.__auraRect) || (el.__auraRect = el.getBoundingClientRect());
      if (rect.width === 0 && rect.height === 0) continue;

      var radius = el.__auraRadius;
      var dist = Aura.dom.distanceToRect(px, py, rect);

      var intensity = 0;
      if (dist < radius) {
        /* Reduced motion: a flat step (see the frame()-level doc comment
           above) instead of the eased power-curve ramp — at most ONE change
           (0 -> 1) as the cursor crosses the radius boundary. */
        intensity = reduced ? 1 : Math.pow(1 - dist / radius, glow.falloff);

        // Route the glow-position to the right coordinate space.
        //
        // Sub-part mode: the host has a .aura-glow__target child whose rim we
        // want to light. The target's viewport rect is derived cheaply from the
        // host rect (one getBoundingClientRect, already in hand) plus the
        // cached relative offset — zero extra layout reads per frame.
        //
        // Standard mode: pointer position is relative to the host, as before.
        var tgt = el.__auraTarget;
        var off = tgt ? el.__auraTargetOff : null;

        if (tgt && off) {
          // Target viewport position derived from cached offset + live host rect.
          var tleft = rect.left + off.dx;
          var ttop  = rect.top  + off.dy;
          tgt.style.setProperty("--aura-glow-x",
            Aura.dom.clamp(px - tleft, 0, off.w) + "px");
          tgt.style.setProperty("--aura-glow-y",
            Aura.dom.clamp(py - ttop,  0, off.h) + "px");
          // --aura-glow-intensity is set on the host below; the target inherits
          // it via CSS cascade. No extra write to the target needed.
        } else {
          // Standard mode: pointer position relative to the host element,
          // clamped to its bounds — the edge-shine hotspot on the rim.
          el.style.setProperty("--aura-glow-x",
            Aura.dom.clamp(px - rect.left, 0, rect.width) + "px");
          el.style.setProperty("--aura-glow-y",
            Aura.dom.clamp(py - rect.top,  0, rect.height) + "px");
        }

        // Magnetic lean: the control glides toward the cursor and KEEPS
        // tracking it even while the cursor is inside, so it stays under the
        // pointer and you can feel where the hover boundary is by how far it
        // has leaned — rather than snapping back to centre the instant you
        // cross in.
        //
        // Direction points from the control's RESTING centre to the cursor;
        // magnitude is the cursor's offset from that centre, capped at
        // --aura-magnet-shift and scaled by proximity (engages gently on
        // approach, tracks 1:1 near the centre). The key is measuring against
        // the *resting* centre — the live rect minus the lean we last applied,
        // minus the hover lift when hovered — not the leaned rect. The
        // reference then never moves as the lean changes, so the control only
        // ever leans TOWARD the cursor (never away): feedback-free, no
        // lean⇄snap oscillation.
        if (el.__auraMagnet) {
          var dx0 = parseFloat(el.style.getPropertyValue("--aura-magnet-dx")) || 0;
          var dy0 = parseFloat(el.style.getPropertyValue("--aura-magnet-dy")) || 0;
          // Hover lift: read a cached flag set by delegated pointerover/pointerout
          // (below) instead of el.matches(":hover"). matches(":hover") resolves a
          // dynamic pseudo-class, forcing style recalc inside the per-frame loop
          // the engine is designed to keep free of forced layout/style work
          // (#41/#43); the cached flag costs nothing per frame (#631).
          var lift = el.__auraHovered ? el.__auraLift : 0;
          var restCx = rect.left + rect.width / 2 - dx0;
          var restCy = rect.top + rect.height / 2 - dy0 + lift;
          var rawx = px - restCx, rawy = py - restCy;
          var rawlen = Math.sqrt(rawx * rawx + rawy * rawy) || 1;
          var mag = Math.min(rawlen, intensity * el.__auraMagnet);
          el.style.setProperty("--aura-magnet-dx", (rawx / rawlen * mag).toFixed(2) + "px");
          el.style.setProperty("--aura-magnet-dy", (rawy / rawlen * mag).toFixed(2) + "px");
        }

        anyActive = true;
      }

      // Group glow: defer the intensity write so a cluster can adopt its
      // strongest member's value; ungrouped elements write immediately.
      if (el.__auraGroup) {
        if (!groupMax) groupMax = {};
        var g = el.__auraGroup;
        if (groupMax[g] === undefined || intensity > groupMax[g]) groupMax[g] = intensity;
      } else {
        applyIntensity(el, intensity);
      }
    }

    // Rects for this pass are now cached; subsequent pointer-only frames reuse
    // them until the next scroll/resize flips rectsDirty back on.
    rectsDirty = false;

    // Second pass: every grouped element adopts its cluster's max intensity, so
    // hovering any one member lights the whole group together.
    if (groupMax) {
      for (var k = 0; k < registry.length; k++) {
        var ge = registry[k];
        if (!ge.__auraGroup || !ge.isConnected) continue;
        applyIntensity(ge, groupMax[ge.__auraGroup] || 0);
      }
    }

    // Keep animating while the cursor is near something or just moved;
    // otherwise idle to save battery (restarts on next pointermove).
    if (anyActive || moved) {
      moved = false;
      requestAnimationFrame(frame);
    } else {
      running = false;
    }
  }

  function start() {
    if (running) return;
    running = true;
    requestAnimationFrame(frame);
  }

  document.addEventListener(
    "pointermove",
    function (e) {
      px = e.clientX;
      py = e.clientY;
      moved = true;
      start();
    },
    { passive: true }
  );

  // Cache hover state on each glow/sheen host via delegated pointer events so
  // frame() can read el.__auraHovered without a per-frame el.matches(":hover")
  // style-recalc (#631). pointerover/pointerout bubble (unlike enter/leave), so
  // one pair of document listeners covers the whole live registry; closest()
  // maps the event target (often a descendant) up to the registered host.
  document.addEventListener("pointerover", function (e) {
    var host = e.target && e.target.closest ? e.target.closest(".aura-glow, .aura-sheen") : null;
    if (host) { host.__auraHovered = true; moved = true; start(); }
  }, { passive: true });
  document.addEventListener("pointerout", function (e) {
    var host = e.target && e.target.closest ? e.target.closest(".aura-glow, .aura-sheen") : null;
    // Ignore moves that stay within the same host (pointerout fires when moving
    // onto a descendant): only clear when the pointer truly left the host.
    if (host && (!e.relatedTarget || !host.contains(e.relatedTarget))) {
      host.__auraHovered = false; moved = true; start();
    }
  }, { passive: true });

  // Viewport/zoom change: advance the style epoch (radius/magnet/lift re-read
  // lazily next frame), flag rects stale, and re-measure target offsets.
  window.addEventListener("resize", function () {
    styleEpoch++;
    rectsDirty = true;
    for (var i = 0; i < registry.length; i++) {
      registry[i].__auraTargetOff = null; // re-read after layout settles
    }
    _scheduleTargetCache();
    moved = true;
    start();
  });

  // Scrolling moves elements within the viewport without firing pointermove, so
  // cached rects must be invalidated and a frame scheduled. Capture-phase +
  // passive catches scrolls on inner scrollers (e.g. the app-shell content)
  // too, since scroll does not bubble. Only a flag is set — cheap per event. */
  document.addEventListener("scroll", function () {
    rectsDirty = true;
    moved = true;
    start();
  }, { capture: true, passive: true });

  // When the pointer leaves the window, fade everything out next frame.
  document.addEventListener("pointerleave", function () {
    px = OFFSCREEN; py = OFFSCREEN; moved = true; start();
  });
})();
